<template><div class="page"><div class="head"><div><h2>{{room.title}}</h2><p>{{room.course_name}} · {{room.teacher_name}}</p></div><el-tag v-if="room.status==='live'" type="danger">直播中</el-tag></div>
<el-alert v-if="error" :title="error" type="error"/><div class="layout"><section><div v-if="room.status==='live'" id="remote-grid" class="video"><span v-if="!connected">正在连接直播流…</span></div><el-empty v-else description="直播已结束"/><div class="bar"><el-button type="danger" plain @click="like">♥ 点赞 {{room.like_count||0}}</el-button><el-button v-if="room.status==='live'" type="primary" plain @click="mic">申请连麦</el-button></div></section>
<aside><h3>互动聊天</h3><div class="messages"><p v-for="m in messages" :key="m.interaction_id"><b>{{m.display_name||m.username}}：</b>{{m.content}}</p></div><div v-if="room.status==='live'" class="send"><el-input v-model="text" maxlength="500" placeholder="文明互动，最多500字" @keyup.enter="send"/><el-button type="primary" @click="send">发送</el-button></div></aside></div></div></template>
<script setup>import{ref,onMounted,onBeforeUnmount,nextTick}from'vue';import{useRoute}from'vue-router';import{ElMessage}from'element-plus';import{roomDetail,sendComment,likeRoom,applyMic}from'../../api/live';import{useLiveRtc}from'../../composables/useLiveRtc';const id=useRoute().params.roomId,room=ref({}),messages=ref([]),text=ref(''),socket=ref();const{connected,error,join,leave}=useLiveRtc(id,'audience');async function refresh(){room.value=await roomDetail(id);messages.value=room.value.interactions||[]}function ws(){const p=location.protocol==='https:'?'wss':'ws';socket.value=new WebSocket(`${p}://${location.host}/ws/live?roomId=${encodeURIComponent(id)}&token=${encodeURIComponent(localStorage.getItem('token'))}`);socket.value.onmessage=refresh}async function send(){if(!text.value.trim())return;await sendComment(id,text.value);text.value='';socket.value?.send('{"type":"refresh"}');refresh()}async function like(){const x=await likeRoom(id);room.value.like_count=x.likeCount;socket.value?.send('{"type":"like"}')}async function mic(){await applyMic(id);ElMessage.success('连麦申请已提交');socket.value?.send('{"type":"mic"}')}onMounted(async()=>{await refresh();if(room.value.status==='live'){await nextTick();try{await join()}catch(e){error.value=e.message}}ws()});onBeforeUnmount(()=>{socket.value?.close();leave()})</script>
<style scoped>.page{background:#fff;padding:20px;border-radius:16px}.head,.layout,.send{display:flex;justify-content:space-between;gap:16px}.head{align-items:center}.head p{color:#64748b}.layout section{flex:1}.layout aside{width:360px;border:1px solid #e5e7eb;border-radius:12px;padding:16px}.video{width:100%;aspect-ratio:16/9;background:#101827;border-radius:12px;color:#fff;display:flex;align-items:center;justify-content:center}.remote{position:absolute}.messages{height:430px;overflow:auto}.bar{padding:14px 0}@media(max-width:900px){.layout{display:block}.layout aside{width:auto}}</style>
